function Parent({ name, age }) {
  // Without useMemo, this object is new every render
  const user = useMemo(() => ({ name, age }), [name, age]);

  return <Child user={user} />;
}

const Child = memo(({ user }) => {
  // Only re‑renders when user reference changes
});
